body.script:
// ===== تأثير الكتابة (Typing Effect) - سطرين =====
const titleElement = document.getElementById('typed-title');
const lines = ["Cybersecurity", "Student"];
let lineIndex = 0;
let charIndex = 0;

function writeText() {
    if (lineIndex < lines.length) {
        if (charIndex < lines[lineIndex].length) {
            titleElement.innerHTML += lines[lineIndex][charIndex];
            charIndex++;
            setTimeout(writeText, 120);
        } else {
            // نهاية السطر الحالي
            if (lineIndex < lines.length - 1) {
                titleElement.innerHTML += "
";
            }
            lineIndex++;
            charIndex = 0;
            setTimeout(writeText, 120);
        }
    }
}

writeText();

// ===== تغيير الخلفية عند hover على الكروت =====
const teamCards = document.querySelectorAll('.team-card');
const mainSection = document.querySelector('.main');
const defaultBg = "url('https://www.cnet.com/a/img/resize/9ec5a14bed80097b4d0004b676714ebbde266ba3/hub/2015/11/10/e7b12806-81cf-4d1c-9be8-5d61e4d15e87/mr-robot-rami-malek.jpg?auto=webp&fit=crop&height=675&width=1200')";

teamCards.forEach(card => {
    card.addEventListener("mouseenter", function () {
        const img = this.querySelector("img");
        if (img && img.getAttribute("src")) {
            const imageUrl = img.getAttribute("src");
            mainSection.style.backgroundImage = `url('${imageUrl}')`;
        }
    });

    card.addEventListener("mouseleave", function () {
        mainSection.style.backgroundImage = defaultBg;
    });
});
